sql:
SELECT COUNT(DISTINCT patients.patient_id)
FROM patients
JOIN medical_history ON patients.patient_id = medical_history.patient_id;

SELECT *
FROM research_data
WHERE de_identified_blood_type = 'O+';

SELECT patient_id, first_name, last_name, chol
FROM patients
WHERE num = 1 AND chol > (SELECT AVG(chol) FROM patients WHERE num = 1);

SELECT COUNT(DISTINCT patient_id) AS num_patients
FROM treatment_records
WHERE treatment_type = 'medication';
